class Solution:
    def constructProductMatrix(self, grid):
        MOD = 12345
        n = len(grid)
        m = len(grid[0])
        flat = [grid[i][j] for i in range(n) for j in range(m)]
        total = len(flat)
        result_flat = [0] * total
        for k in range(total):
            prod = 1
            for t in range(total):
                if t == k:
                    continue
                prod = (prod * (flat[t] % MOD)) % MOD
            result_flat[k] = prod
        p = [[0] * m for _ in range(n)]
        for idx in range(total):
            p[idx // m][idx % m] = result_flat[idx]
        return p

