var constructProductMatrix = function(grid) {
    const MOD = 12345;
    const n = grid.length;
    const m = grid[0].length;
    const flat = [];
    for (let i = 0; i < n; i++) for (let j = 0; j < m; j++) flat.push(grid[i][j]);
    const total = flat.length;
    const prefix = new Array(total + 1).fill(1);
    for (let k = 0; k < total; k++) {
        prefix[k + 1] = (prefix[k] * (flat[k] % MOD)) % MOD;
    }
    const suffix = new Array(total + 1).fill(1);
    for (let k = total - 1; k >= 0; k--) {
        suffix[k] = (suffix[k + 1] * (flat[k] % MOD)) % MOD;
    }
    const p = [];
    for (let i = 0; i < n; i++) p.push(new Array(m).fill(0));
    for (let idx = 0; idx < total; idx++) {
        const val = (prefix[idx] * suffix[idx + 1]) % MOD;
        p[Math.floor(idx / m)][idx % m] = val;
    }
    return p;
};
